const item = $input.first();

let saida = '';

if (item.json.output) {
  saida = item.json.output
    .replace(/\\n/g, '\n')   // normaliza primeiro
    .replace(/\n/g, '\\n')   // depois escapa corretamente
    .replace(/\r/g, '')
    .trim();
}

return [
  {
    json: {
      mensagem: saida
    }
  }
];

